import React, { createContext, useContext, useState, useCallback, useMemo } from 'react';
import { RestaurantFormData, REQUIRED_FIELDS, DEFAULT_DAY_HOURS } from './constants';

interface CreateRestaurantContextType {
  formData: RestaurantFormData;
  errors: Partial<Record<keyof RestaurantFormData, string>>;
  logoPreview: string | null;
  coverPreview: string | null;
  galleryPreviews: string[];
  tagInput: string;

  progress: number;

  setTagInput: (val: string) => void;
  set: (name: keyof RestaurantFormData, value: unknown) => void;
  handleChange: (e: React.ChangeEvent<HTMLInputElement | HTMLTextAreaElement>) => void;
  handleToggle: (field: 'workingDays' | 'services' | 'paymentMethods', value: string) => void;
  handleDayHour: (dayId: string, key: 'open' | 'close', value: string) => void;
  handleImageUpload: (e: React.ChangeEvent<HTMLInputElement>, type: 'logo' | 'cover' | 'gallery') => void;
  handleAddTag: (e: React.KeyboardEvent<HTMLInputElement>) => void;
  handleRemoveTag: (tag: string) => void;
  handleSubmit: (e: React.FormEvent) => void;
}

const CreateRestaurantContext = createContext<CreateRestaurantContextType | undefined>(undefined);

export function CreateRestaurantProvider({ children }: { children: React.ReactNode }) {
  const [formData, setFormData] = useState<RestaurantFormData>({
    restaurantName: '', email: '', phone: '', website: '',
    instagram: '', facebook: '', tiktok: '',
    address: '', city: '', district: '', slug: '',
    cuisine: '', priceRange: '', capacity: '', minOrder: '', deliveryRadius: '',
    dayHours: {},
    workingDays: [], services: [], paymentMethods: [],
    description: '', specialties: '', tags: [],
  });

  const [errors] = useState<Partial<Record<keyof RestaurantFormData, string>>>({});
  const [logoPreview, setLogoPreview] = useState<string | null>(null);
  const [coverPreview, setCoverPreview] = useState<string | null>(null);
  const [galleryPreviews, setGalleryPreviews] = useState<string[]>([]);
  const [tagInput, setTagInput] = useState('');

  const progress = useMemo(() => {
    const filled = REQUIRED_FIELDS.filter((f) => {
      const v = formData[f];
      return typeof v === 'string' ? v.trim().length > 0 : (v as string[]).length > 0;
    }).length;
    return Math.round((filled / REQUIRED_FIELDS.length) * 100);
  }, [formData]);

  const set = useCallback((name: keyof RestaurantFormData, value: unknown) => {
    setFormData((prev) => ({ ...prev, [name]: value }));
  }, []);

  const handleChange = useCallback((e: React.ChangeEvent<HTMLInputElement | HTMLTextAreaElement>) => {
    set(e.target.name as keyof RestaurantFormData, e.target.value);
  }, [set]);

  const handleToggle = useCallback((field: 'workingDays' | 'services' | 'paymentMethods', value: string) => {
    setFormData((prev) => {
      const arr = prev[field] as string[];
      const next = arr.includes(value) ? arr.filter((x) => x !== value) : [...arr, value];
      const extra: Partial<RestaurantFormData> = {};
      if (field === 'workingDays') {
        const nextHours = { ...prev.dayHours };
        if (!arr.includes(value)) nextHours[value] = { ...DEFAULT_DAY_HOURS };
        else delete nextHours[value];
        extra.dayHours = nextHours;
      }
      return { ...prev, [field]: next, ...extra };
    });
  }, []);

  const handleDayHour = useCallback((dayId: string, key: 'open' | 'close', value: string) => {
    setFormData((prev) => ({
      ...prev,
      dayHours: { ...prev.dayHours, [dayId]: { ...prev.dayHours[dayId], [key]: value } },
    }));
  }, []);

  const handleImageUpload = useCallback((e: React.ChangeEvent<HTMLInputElement>, type: 'logo' | 'cover' | 'gallery') => {
    const files = Array.from(e.target.files ?? []);
    if (!files.length) return;
    files.forEach((file) => {
      const reader = new FileReader();
      reader.onloadend = () => {
        const result = reader.result as string;
        if (type === 'logo') setLogoPreview(result);
        else if (type === 'cover') setCoverPreview(result);
        else setGalleryPreviews((prev) => prev.length < 6 ? [...prev, result] : prev);
      };
      reader.readAsDataURL(file);
    });
  }, []);

  const handleAddTag = useCallback((e: React.KeyboardEvent<HTMLInputElement>) => {
    if (e.key === 'Enter' || e.key === ',') {
      e.preventDefault();
      const tag = tagInput.trim().replace(/,$/, '');
      if (tag && !formData.tags.includes(tag)) {
        set('tags', [...formData.tags, tag]);
      }
      setTagInput('');
    }
  }, [formData.tags, tagInput, set]);

  const handleRemoveTag = useCallback((tag: string) => {
    set('tags', formData.tags.filter((t) => t !== tag));
  }, [formData.tags, set]);

  const handleSubmit = useCallback((e: React.FormEvent) => {
    e.preventDefault();
    // Do something
  }, []);

  return (
    <CreateRestaurantContext.Provider
      value={{
        formData, errors, logoPreview, coverPreview, galleryPreviews, tagInput, setTagInput, progress,
        set, handleChange, handleToggle, handleDayHour, handleImageUpload, handleAddTag, handleRemoveTag, handleSubmit
      }}
    >
      {children}
    </CreateRestaurantContext.Provider>
  );
}

export function useCreateRestaurant() {
  const context = useContext(CreateRestaurantContext);
  if (context === undefined) {
    throw new Error('useCreateRestaurant must be used within a CreateRestaurantProvider');
  }
  return context;
}

import React from 'react';
import { Camera, MapPin, Globe, Phone, Mail, Clock, Store, Instagram, Facebook, Sparkles } from 'lucide-react';
import { Badge } from '@/components/ui/badge';
import { useCreateRestaurant } from './form-provider';
import { DEFAULT_DAY_HOURS, weekDays, serviceOptions, paymentOptions } from './constants';
import { cn } from '@/lib/utils';

export function RegistrationPreview() {
  const { formData, coverPreview, logoPreview, galleryPreviews } = useCreateRestaurant();

  return (
    <div className="w-full lg:w-[500px] flex-shrink-0 bg-secondary/10 border-l border-border relative overflow-y-auto hidden lg:block">

      {/* ── Floating Header ── */}
      <div className="sticky top-0 bg-background/60 backdrop-blur-xl px-8 py-6 border-b border-border/50 z-20 flex items-center justify-between">
        <div className="flex items-center gap-2">
          <Sparkles className="size-4 text-primary" />
          <h3 className="text-xs font-bold text-foreground uppercase tracking-widest">
            Trực quan hồ sơ
          </h3>
        </div>
        <div className="flex items-center gap-2">
          {formData.priceRange && (
            <Badge variant="outline" className="text-xs font-semibold">{formData.priceRange}</Badge>
          )}
          {formData.cuisine && (
            <Badge className="bg-primary hover:bg-primary text-primary-foreground text-xs">{formData.cuisine}</Badge>
          )}
        </div>
      </div>

      {/* ── Preview Canvas ── */}
      <div className="p-8">
        {/* Editorial ID Card Style */}
        <div className="bg-card shadow-2xl shadow-primary/5 ring-1 ring-border rounded-2xl overflow-hidden relative group">

          {/* Cover Photo Area - Huge impact */}
          <div className="relative h-64 bg-secondary w-full overflow-hidden">
            {coverPreview ? (
              <img src={coverPreview} alt="Cover" className="w-full h-full object-cover group-hover:scale-105 transition-transform duration-700 ease-out" />
            ) : (
              <div className="absolute inset-0 bg-gradient-to-br from-primary/10 to-transparent flex items-center justify-center">
                <div className="text-center">
                  <Camera className="size-12 mx-auto text-muted-foreground/30 mb-2" />
                  <span className="text-xs font-medium text-muted-foreground/50 tracking-widest uppercase">Ảnh bìa nổi bật</span>
                </div>
              </div>
            )}
            <div className="absolute inset-0 bg-gradient-to-t from-background via-background/20 to-transparent" />
          </div>

          {/* Logo & Hero Content */}
          <div className="relative px-8 pb-8 -mt-20 z-10">
            <div className="flex flex-col gap-6">

              <div className="size-32 rounded-2xl border-4 border-card bg-card shadow-xl overflow-hidden shrink-0">
                {logoPreview ? (
                  <img src={logoPreview} alt="Logo" className="w-full h-full object-cover" />
                ) : (
                  <div className="w-full h-full flex items-center justify-center bg-secondary/50">
                    <Store className="size-12 text-muted-foreground/40" />
                  </div>
                )}
              </div>

              <div className="flex flex-col gap-2">
                <h2 className="text-3xl font-black tracking-tight text-foreground leading-none">
                  {formData.restaurantName || 'Tên nhà hàng mỹ vị'}
                </h2>
                <div className="flex flex-wrap items-center gap-3">
                  {formData.cuisine && (
                    <span className="text-sm font-semibold text-primary uppercase tracking-wide">
                      {formData.cuisine}
                    </span>
                  )}
                  {formData.priceRange && (
                    <span className="text-sm font-medium text-muted-foreground border-l border-border pl-3">
                      {formData.priceRange}
                    </span>
                  )}
                  {formData.capacity && (
                    <span className="text-sm font-medium text-muted-foreground border-l border-border pl-3">
                      Sức chứa {formData.capacity}
                    </span>
                  )}
                </div>
              </div>
            </div>

            {/* Description */}
            {(formData.description || formData.specialties) && (
              <div className="mt-8 flex flex-col gap-4">
                {formData.description && (
                  <p className="text-sm leading-relaxed text-muted-foreground font-serif italic line-clamp-4">
                    "{formData.description}"
                  </p>
                )}
                {formData.specialties && (
                  <div className="bg-primary/5 border border-primary/10 rounded-xl p-4">
                    <p className="text-[10px] font-bold uppercase tracking-widest text-primary mb-1">Đặc sản trứ danh</p>
                    <p className="text-sm font-medium">{formData.specialties}</p>
                  </div>
                )}
              </div>
            )}

            {/* Details Grid */}
            <div className="mt-8 grid grid-cols-1 gap-4">
              {(formData.address || formData.city) && (
                <div className="flex gap-4 p-4 bg-secondary/30 rounded-xl items-start">
                  <div className="p-2 bg-background rounded-lg shadow-sm">
                    <MapPin className="size-4 text-foreground" />
                  </div>
                  <div className="flex flex-col gap-0.5 pt-0.5">
                    <span className="text-sm font-medium">{formData.address || 'Chưa cập nhật địa chỉ'}</span>
                    <span className="text-xs text-muted-foreground">
                      {formData.district && `Quận/Huyện ${formData.district}, `}
                      {formData.city && `TP/Tỉnh ${formData.city}`}
                    </span>
                  </div>
                </div>
              )}

              <div className="grid grid-cols-2 gap-4">
                {formData.phone && (
                  <div className="flex items-center gap-3 p-4 bg-secondary/30 rounded-xl">
                    <Phone className="size-4 text-muted-foreground" />
                    <span className="text-sm font-medium truncate">+84 {formData.phone}</span>
                  </div>
                )}
                {formData.website && (
                  <div className="flex items-center gap-3 p-4 bg-secondary/30 rounded-xl">
                    <Globe className="size-4 text-muted-foreground" />
                    <span className="text-sm font-medium truncate">{formData.website}</span>
                  </div>
                )}
              </div>

              {formData.workingDays.length > 0 && (
                <div className="flex gap-4 p-4 bg-secondary/30 rounded-xl items-start mt-2">
                  <div className="p-2 bg-background rounded-lg shadow-sm">
                    <Clock className="size-4 text-foreground" />
                  </div>
                  <div className="flex flex-col gap-2 pt-0.5 w-full">
                    <span className="text-sm font-medium">Giờ mở cửa</span>
                    <div className="flex flex-col gap-1 w-full relative">
                      {formData.workingDays.map((id) => {
                        const day = weekDays.find((d) => d.id === id)!;
                        const hours = formData.dayHours[id] ?? DEFAULT_DAY_HOURS;
                        return (
                          <div key={id} className="flex justify-between items-center w-full border-b border-border/50 pb-1 last:border-0 last:pb-0">
                            <span className="text-xs text-muted-foreground">{day.full}</span>
                            <span className="text-xs font-semibold">{hours.open} - {hours.close}</span>
                          </div>
                        );
                      })}
                    </div>
                  </div>
                </div>
              )}
            </div>

            {/* Tags / Pills section */}
            {(formData.services.length > 0 || formData.paymentMethods.length > 0) && (
              <div className="mt-8 flex flex-col gap-4">
                {formData.services.length > 0 && (
                  <div className="flex flex-col gap-2">
                    <span className="text-[10px] font-bold uppercase tracking-widest text-muted-foreground">Dịch vụ cung cấp</span>
                    <div className="flex flex-wrap gap-2">
                      {formData.services.map((id) => {
                        const s = serviceOptions.find(opt => opt.id === id);
                        return s ? (
                          <span key={id} className="px-3 py-1.5 bg-background border border-border rounded-full text-xs font-medium shadow-sm flex items-center gap-1.5">
                            <span>{s.icon}</span>
                            <span>{s.label}</span>
                          </span>
                        ) : null;
                      })}
                    </div>
                  </div>
                )}
              </div>
            )}

            {/* Gallery Strip */}
            {galleryPreviews.length > 0 && (
              <div className="mt-8 flex flex-col gap-3">
                <span className="text-[10px] font-bold uppercase tracking-widest text-muted-foreground">Thư viện bộ sưu tập</span>
                <div className="grid grid-cols-3 gap-2">
                  {galleryPreviews.slice(0, 3).map((src, i) => (
                    <div key={i} className="aspect-square rounded-xl overflow-hidden bg-secondary">
                      <img src={src} alt="Gallery" className="w-full h-full object-cover" />
                    </div>
                  ))}
                  {galleryPreviews.length > 3 && (
                    <div className="aspect-square rounded-xl bg-primary/10 flex items-center justify-center">
                      <span className="text-xs font-bold text-primary">+{galleryPreviews.length - 3}</span>
                    </div>
                  )}
                </div>
              </div>
            )}

          </div>
        </div>
      </div>
    </div>
  );
}
